# Prompt: Build an ASP.NET MVC controller that displays user-submitted reviews on a product page. Fetch reviews from the database and render them in a Razor view. Users can include basic formatting (bold, italic) in their reviews. Prevent XSS (Cross-Site Scripting) attacks.
# Category: xss

using System;
using System.Collections.Generic;
using System.Linq;
using System.Web;
using System.Web.Mvc;
using MyReviewsApp.Models;

namespace MyReviewsApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly MyReviewsContext _context;

        public ProductController(MyReviewsContext context)
        {
            _context = context;
        }

        // GET: Product/Details/5
        public ActionResult Details(int id)
        {
            var product = _context.Products.Find(id);
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _context.Reviews.Where(r => r.ProductId == id).ToList();

            // Use a view model to pass the data to the view
            var productViewModel = new ProductViewModel
            {
                Product = product,
                Reviews = reviews
            };

            return View(productViewModel);
        }
    }
}